INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("フフ、全問正解よ！\nちゃんと勉強してるみたいで\n感心だわ♪", 1, 4, 10, 1, 3001, 10, 3.18, 8, 7, 11300101, 1, "vo_minigame_1012_result_1000");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("すごいじゃない…全問正解よ！\nま、当然といや当然よね～\nだってあたしが\n教えてやってんだから♪", 1, 10, 10, 1, 3001, 10, 3.33, 7, 8, 11300102, 1, "vo_minigame_1012_result_1001");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("全問正解！　パチパチパチ～♪\nこの難易度はもう完璧じゃない？\n次はもっと難しい問題に挑戦よ！\nあんたならできるって！", 1, 10, 10, 1, 3001, 10, 5.41, 1, 8, 11300103, 1, "vo_minigame_1012_result_1002");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("へえ…難しい問題を選んだのに\n全問正解できてるじゃない！！\nちょっとあんたすごすぎだわ…！\nパーフェクトよパーフェクト！", 1, 10, 10, 2, 3001, 10, 8.11, 8, 5, 11300104, 1, "vo_minigame_1012_result_1003");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("まる…まる…全部まる！\n難しい問題なのに全問正解よ…！\n驚いた…あんたいつの間に、\nこんなに勉強してたのよ！", 1, 0, 10, 2, 3001, 10, 1.31, 5, 10, 11300105, 1, "vo_minigame_1012_result_1004");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ここまで完璧に正解されちゃうと\nちょっと悔しいわね…！\nけど素直に褒めてやるわ！\nえらい、えらい、えら～い！", 1, 0, 10, 2, 3001, 10, 4.93, 8, 9, 11300106, 1, "vo_minigame_1012_result_1005");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("すごい…あんたパーフェクトよ！\nこのままいけば次の試験、\n学年一位も夢じゃないかもね！\n楽しみだわ～♪", 1, 4, 10, 3, 3001, 10, 2.99, 8, 5, 11300107, 1, "vo_minigame_1012_result_1006");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("満点よ！　フフ、もうあんたに\n教えることはなにもないわ…！\n逆にあたしがあんたに教わりたい\nくらいよ！　…ね、先生♪", 1, 4, 10, 3, 3001, 10, 8.37, 7, 8, 11300108, 1, "vo_minigame_1012_result_1007");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("全・問・正・解！\n超難問揃いなのにすごいわね…！\nもしかしてだけど、\nあんたって天才！？", 1, 8, 10, 3, 3001, 10, 5.32, 5, 7, 11300109, 1, "vo_minigame_1012_result_1008");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("お、かなりいい点数ね～！\nあたしも教えがいがあるわ♪\nさ、まだまだ勉強するわよ！", 1, 4, 9, 1, 3001, 7, 4.77, 1, 7, 11300110, 1, "vo_minigame_1012_result_1009");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うん、いい感じで点取れてるわ！\nこの調子で次は、\n満点を見せてほしいわね！", 1, 4, 9, 1, 3001, 7, 2.97, 7, 8, 11300111, 1, "vo_minigame_1012_result_1010");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("あ～惜しい！\nもうちょっとで満点じゃない！\n次はパーフェクトいけるわ！\n頑張りましょ！", 1, 0, 9, 1, 3001, 7, 3.47, 1, 5, 11300112, 1, "vo_minigame_1012_result_1011");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("すごい、かなりできてるわよ！\n難しい問題なのにやるじゃない！\nあとは目指せ、満点ね！", 1, 4, 9, 2, 3001, 7, 5.32, 7, 8, 11300113, 1, "vo_minigame_1012_result_1012");
