INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("あーあとちょっとで\n全問正解だったのに！\n難しい問題だけどあんたなら\n次は満点狙えるわ！", 1, 0, 9, 2, 3001, 7, 3.56, 1, 5, 11300115, 1, "vo_minigame_1012_result_1014");
