INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うわー惜しいわね！\nもうちょっとで満点よ？\nま、あたしでも悩む難問だから、\nこの点数は胸を張っていいわ！", 1, 0, 9, 3, 3001, 7, 3.88, 1, 5, 11300118, 1, "vo_minigame_1012_result_1017");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("正解率は半分くらいか～\n悪くはないんだけど、あんたなら\nこんなもんじゃないでしょ？", 1, 0, 6, 1, 3001, 4, 4.12, 1, 3, 11300119, 1, "vo_minigame_1012_result_1018");
