INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("半分くらいの正解率か\n難しい問題だから仕方ないわね…\nでもあんたはもっとできる！\nだってあたしがついてんのよ！", 1, 0, 6, 2, 3001, 4, 5.3, 1, 9, 11300122, 1, "vo_minigame_1012_result_1021");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うん、そこそこできんじゃない！\n頑張って勉強して\nさらに上を目指しましょ！", 1, 0, 6, 2, 3001, 4, 2.55, 1, 8, 11300123, 1, "vo_minigame_1012_result_1022");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("難問なのにこの正解率は\nよくやってる方よね！\nでもこんなところで\n満足してんじゃないわよ！？", 1, 0, 6, 2, 3001, 4, 4.19, 7, 1, 11300124, 1, "vo_minigame_1012_result_1023");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("難問なのに半分くらい正解\nできてんじゃない♪\nこの調子でもっと学力\n上げていきましょ！", 1, 0, 6, 3, 3001, 4, 3.43, 1, 7, 11300125, 1, "vo_minigame_1012_result_1024");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("よし、平均点ってとこね！\nちゃんと勉強してるみたいで\n安心したわ～♪", 1, 0, 6, 3, 3001, 4, 0.0, 1, 1, 11300126, 1, "vo_minigame_1012_result_1025");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("難問揃いでこの正解率は\n大したもんよ！\nま、もっといい点取りたいんなら\n勉強、付き合ったげるわ！", 1, 0, 6, 3, 3001, 4, 3.72, 7, 8, 11300127, 1, "vo_minigame_1012_result_1026");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("なるほど…\nこれは教えがいがあるわね\nビシバシ鍛えてやるから\n覚悟しなさい！", 1, 1, 3, 1, 3001, 1, 3.5, 2, 3, 11300128, 1, "vo_minigame_1012_result_1027");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ちょっとあんた、\n全然できてないじゃない！\n…まさかこれが本気だなんて\n言わないわよね～？", 1, 1, 3, 1, 3001, 1, 3.25, 2, 4, 11300129, 1, "vo_minigame_1012_result_1028");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うーん……適当に答えても\nこれくらい正解できるわよ？\nちょっと本腰入れて\n教えないとね……！", 1, 0, 3, 1, 3001, 1, 4.62, 2, 3, 11300130, 1, "vo_minigame_1012_result_1029");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("…ま、まあこの問題は\nあんたには難しすぎたのかもね\nちょっとずつでいいから、\nレベルアップしていきましょ！", 1, 0, 3, 2, 3001, 1, 4.5, 1, 9, 11300131, 1, "vo_minigame_1012_result_1030");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("んー結構ミスっちゃってるわね…\nこのまま続けるのもいいけど、\n簡単な問題からやり直すのも\nありかもよ～？", 1, 9, 3, 2, 3001, 1, 0.01, 3, 3, 11300132, 1, "vo_minigame_1012_result_1031");
