INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うーん、残念な結果ね…\n超難問だから仕方ないけど\n無理せず簡単な問題から挑戦\nしてもいいかもよ？", 1, 6, 3, 3, 3001, 1, 0.01, 3, 3, 11300134, 1, "vo_minigame_1012_result_1033");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("正解率はかなり悪いわね…\nまあ難しい問題だもんね…！\nそのチャレンジ精神は買うわ！", 1, 0, 3, 3, 3001, 1, 2.97, 9, 3, 11300135, 1, "vo_minigame_1012_result_1034");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("なんとか０点は免れたわね…\n難問揃いだけど、\nもっと頑張っていきましょ！", 1, 0, 3, 3, 3001, 1, 3.1, 1, 3, 11300136, 1, "vo_minigame_1012_result_1035");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("…あんたさ、０点なんて\n逆に取るの難しいわよ！？\nまさか狙ったわけじゃ\nないでしょーね～！？", 1, 1, 0, 1, 3001, 0, 4.31, 2, 6, 11300137, 1, "vo_minigame_1012_result_1036");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("０点って…\nあんたふざけてんの！？\nちゃんとやらないなら\n電撃魔法くらわせるわよ！？", 1, 1, 0, 1, 3001, 0, 0.1, 2, 2, 11300138, 1, "vo_minigame_1012_result_1037");
