INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("怒んないから正直に言って？\n…ふざけて答えたでしょ？\nほら、正直に\n言・い・な・さ・い？", 1, 0, 0, 2, 3001, 0, 4.38, 2, 3, 11300140, 1, "vo_minigame_1012_result_1039");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("あんたの点数は～～…\n…はい！　０てーん！！\n…って、ふざけんなーー！！！", 1, 0, 0, 2, 3001, 0, 3.58, 2, 8, 11300141, 1, "vo_minigame_1012_result_1040");
