INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("はい、よくできました！\n基礎はもう完璧ね！\n次はもっと難しい問題にも\nチャレンジしちゃいなさいよ！", 1, 10, -1, 1, 3001, 20, 3.74, 1, 7, 12300101, 2, "vo_minigame_1012_result_1045");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("なによあんた、走り出したペンが\n止まらないって感じ？\nったくシンプルにすごいじゃない\n花丸あげるわ！", 1, 0, -1, 1, 3001, 20, 3.85, 9, 1, 12300102, 2, "vo_minigame_1012_result_1046");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("すごい点数ね…！\nあんた勉強してないとか言って\nホントはめちゃくちゃやってる\nパターンのやつね！？", 1, 8, -1, 1, 3001, 20, 0.01, 5, 5, 12300103, 2, "vo_minigame_1012_result_1047");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("勉強の成果、\nちゃんとでてんじゃない！\nあたしもあんたの先生として、\n鼻が高いわ～♪", 1, 4, -1, 2, 3001, 20, 2.86, 7, 8, 12300104, 2, "vo_minigame_1012_result_1048");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("オッケー！　もう十分よ！\nこれ以上でき過ぎちゃったら、\nあたしが教える必要なくなるわ！", 1, 9, -1, 2, 3001, 20, 2.02, 3, 5, 12300105, 2, "vo_minigame_1012_result_1049");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("難しい問題を選んだつもりなのに\nすごい正解数ね…！\nでもまだ上がある…\n次は最難関に挑戦よ！", 1, 0, -1, 2, 3001, 20, 4.46, 1, 5, 12300106, 2, "vo_minigame_1012_result_1050");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("すごいすごいとは思ってたけど、\nあんた勉強も完璧なの…？\nそりゃみんなあんたに惚れ…\nや、な、なんでもない！！", 1, 7, -1, 3, 3001, 20, 6.85, 4, 5, 12300107, 2, "vo_minigame_1012_result_1051");
