INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("別に顔赤くなんてなってない！\n頭がいい人が好きとか…\nかっこいいとか…\n…思ってないからね！", 1, 7, -1, 3, 3001, 20, 0.01, 4, 4, 12300109, 2, "vo_minigame_1012_result_1053");
