INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("スピードも正確さも完璧…\n文句なしの満点だわ！\nあんた将来、とんでもない人に\nなっちゃうんじゃない！？", 1, 0, -1, 2, 3001, 20, 0.0, 5, 5, 12300112, 2, "vo_minigame_1012_result_1054");
