INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うん、頑張ったけど…\n正直もっと正解できるかもね～？\nこんなのあんたには通過点！\nさらに良い点目指してみない？", 1, 0, 9, 1, 3001, 5, 4.74, 1, 7, 12300147, 2, "vo_minigame_1012_result_1079");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("まあまあな点数だけど、\n自分的に手ごたえはどう？\nダメだって思ってんなら、\nまだまだ伸びる余地ありね！", 1, 0, 9, 1, 3001, 5, 0.0, 1, 1, 12300148, 2, "vo_minigame_1012_result_1080");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うん、中々の出来ね！\nでもあんたはもっといい点\n取れるはずよ！\nもっと頑張りましょうか！", 1, 0, 9, 2, 3001, 5, 2.21, 1, 8, 12300149, 2, "vo_minigame_1012_result_1081");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ん～はっきり言って微妙ね！\nま、難しい問題だし、\n勉強すれば\n点数は上がっていくと思うわ！", 1, 0, 9, 2, 3001, 5, 2.46, 1, 3, 12300150, 2, "vo_minigame_1012_result_1082");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ん～…\n10点には届かなかったか～\n次は10点越え目指して\n頑張ってみない？", 1, 0, 9, 2, 3001, 5, 2.94, 1, 3, 12300151, 2, "vo_minigame_1012_result_1083");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("はいお疲れ～\n点数的にはまあまあってとこね！\nま、超難問だし頑張ったわよ", 1, 0, 9, 3, 3001, 5, 4.19, 1, 7, 12300152, 2, "vo_minigame_1012_result_1084");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うん、かなり難しい問題なのに\n最後までやり遂げたわね\n次はもっといい点目指してみる？", 1, 0, 9, 3, 3001, 5, 0.0, 1, 1, 12300153, 2, "vo_minigame_1012_result_1085");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ちょっとミスが多かったかもね～\nでも間違えた所は復習して\n次は正解するわよー！", 1, 0, 9, 3, 3001, 5, 2.63, 1, 3, 12300154, 2, "vo_minigame_1012_result_1086");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("あら…あんまり良くない点数ね～\nどうしたの、調子でも悪かった？\n次はもっと頑張りましょうか", 1, 0, 4, 1, 3001, 1, 5.53, 1, 3, 12300155, 2, "vo_minigame_1012_result_1087");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ん～…正解数は\n物足りないわね～\nもうちょっと勉強の時間\n増やしちゃおっか？", 1, 9, 4, 1, 3001, 1, 0.01, 3, 3, 12300156, 2, "vo_minigame_1012_result_1088");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ん～…あんたならもうちょと\nいい点取れんでしょ～？\nもっと頑張んなさいよ\n期待してやってんだからさ！", 1, 3, 4, 1, 3001, 1, 4.15, 1, 3, 12300157, 2, "vo_minigame_1012_result_1089");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ん～今のあんたには、\nこの問題は難しかったかしら…\n難易度下げてチャレンジするのも\nありかもね～？", 1, 9, 4, 2, 3001, 1, 0.01, 9, 9, 12300158, 2, "vo_minigame_1012_result_1090");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("あんまり出来は良くないわね～\n難しい問題だししょうがないけど\n次はもっと頑張ってほしいわ！", 1, 0, 4, 2, 3001, 1, 5.37, 1, 3, 12300159, 2, "vo_minigame_1012_result_1091");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("なるほど…\nちょっと苦手な問題が多かった？\nもう一度チャレンジ\nしてみましょうか～", 1, 0, 4, 2, 3001, 1, 1.44, 1, 3, 12300160, 2, "vo_minigame_1012_result_1092");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("んん～…問題が難しすぎた？\n無理に難しい問題続けるより、\n難易度下げた方が\n勉強の効率良いかもよ～？", 1, 0, 4, 3, 3001, 1, 0.0, 3, 3, 12300161, 2, "vo_minigame_1012_result_1093");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("…あんまり点数取れなかったわね\nこれはあたしにも難しい問題だし\nそう落ち込まなくても大丈夫！\n次頑張りましょ！", 1, 3, 4, 3, 3001, 1, 2.91, 9, 3, 12300162, 2, "vo_minigame_1012_result_1094");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ごめん、ちょっと難しすぎた？\nもう一度チャレンジするも良し、\n難易度を下げるも良し、\nあんたがやる気なら付き合うわ！", 1, 0, 4, 3, 3001, 1, 2.61, 1, 5, 12300163, 2, "vo_minigame_1012_result_1095");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ちょっとあんた…\nやる気ないわよね～！？\n次こんな点数取ったら\n怒るわよ！", 1, 1, 0, 1, 3001, 0, 3.63, 2, 4, 12300164, 2, "vo_minigame_1012_result_1096");
