INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("うう～頭痛い…\nあんたのせいよ！\nなに０点って！\nはあ、このままじゃ赤点よ～…", 1, 6, 0, 1, 3001, 0, 0.01, 3, 3, 12300166, 2, "vo_minigame_1012_result_1098");
