INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("あ…あんた、０点よ０点…！\nあたしの教え方が悪かった…？\n…燃えてきたわ！\n絶対あんたの学力上げてやる！", 1, 1, 0, 2, 3001, 0, 5.64, 2, 4, 12300168, 2, "vo_minigame_1012_result_1100");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ちょっと待って採点ミスかも…\n…いや合ってるわね。はい０点\n…って０点！？\nふざけんなーー！", 1, 8, 0, 2, 3001, 0, 5.73, 4, 8, 12300169, 2, "vo_minigame_1012_result_1101");
