INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("おにムズ過ぎてテンサゲ～\nでもヒデサイがんばってるし\nうちもがんばる！", 2, 0, 4, 3, 3001, 1, 3.14, 5, 9, 22300162, 2, "vo_minigame_1012_result_2094");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("ヒデサイと同じ点数で\nちょっち安心したかも\n一緒にがんばろーね！\n置いてっちゃやだよ？", 2, 0, 4, 3, 3001, 1, 6.59, 4, 7, 22300163, 2, "vo_minigame_1012_result_2095");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("…まあ、これより下はないし\n次は大逆転\n点数爆上がりっしょ！", 2, 0, 0, 1, 3001, 0, 0.0, 3, 3, 22300164, 2, "vo_minigame_1012_result_2096");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("０点じゃん…\nそだ、次はえんぴつ転がして\n選ぶ作戦やってみる？", 2, 5, 0, 1, 3001, 0, 2.2, 10, 9, 22300165, 2, "vo_minigame_1012_result_2097");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("考えるの無理な時あるよね…\nヒデサイもそーゆう\n感じだったの？", 2, 6, 0, 1, 3001, 0, 0.01, 4, 4, 22300166, 2, "vo_minigame_1012_result_2098");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("え、ヒデサイも０点？\nじゃあうちと一緒じゃん♪\nまあ焦んないで\nベンキョーしてこーよ！", 2, 3, 0, 2, 3001, 0, 2.8, 2, 6, 22300167, 2, "vo_minigame_1012_result_2099");
INSERT INTO `v1_9db591471d6b5c2f0c826d6b29c711b598c853f801cd8932cf2b816102e4112e` VALUES ("むむむ～…０点…！\n覚えてもすぐ忘れちゃうし\nベンキョーってマジ大変", 2, 6, 0, 2, 3001, 0, 3.22, 4, 9, 22300168, 2, "vo_minigame_1012_result_2100");
